body:
an example of how it's different is:

```ts
import { Expand, UiState } from './types';

type mix = UiState & { [index: string]: { swag?: boolean } };
type mixExpand = Expand<mix>;

// @ts-expect-error
const initialUiState: mix = {
  someIndex: {
    swag: true,
  },
};

const initialUiStateExpanded: mixExpand = {
  someIndex: {
    swag: true,
  },
};
```
